using System;
using System.Net;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Host;
using Microsoft.Extensions.Logging;

namespace MyFunctionApp
{
    public static class MyHttpTriggeredFunction
    {
        [FunctionName("MyHttpTriggeredFunction")]
        public static IActionResult Run(
            [HttpTrigger(AuthorizationLevel.Anonymous, "get", "post", Route = null)] HttpRequest req,
            ILogger log)
        {
            log.LogInformation($"C# HTTP trigger function processed a request. RequestUri={req.Url}");

            // Log HTTP request headers
            foreach (var header in req.Headers)
            {
                log.LogInformation($"Header: {header.Key}, Value: {header.Value}");
            }

            // Log HTTP request body content
            var requestBody = await new StreamReader(req.Body).ReadToEndAsync();
            log.LogInformation($"Request Body: {requestBody}");

            // Log database queries with parameters
            using (var connection = new SqlConnection("connectionString"))
            {
                connection.Open();
                var command = new SqlCommand("SELECT * FROM MyTable", connection);
                var reader = command.ExecuteReader();
                while (reader.Read())
                {
                    log.LogInformation($"Database Query Result: {reader["MyColumn"]}");
                }
            }

            // Log full exception details
            try
            {
                throw new Exception("This is a test exception");
            }
            catch (Exception ex)
            {
                log.LogError(ex, "An error occurred while processing the request");
            }

            return new OkResult();
        }
    }
}